// svg 落 shadow;container(element) 直传 shadow 内节点(接受 DOM 元素或选择器)。正常渲染不触 body(仅导出 <a download> 会)。
import { OrgChart } from 'https://cdn.jsdelivr.net/npm/d3-org-chart@3.1.1/+esm';
const el = document.createElement('div'); el.style.width = '100%'; el.style.height = '600px'; shadowRoot.appendChild(el);
const chart = new OrgChart().container(el).svgHeight(600).data(data.nodes).render();

